import json
import re

funding_file = var_functions.query_db:2
civic_file = var_functions.query_db:5

with open(funding_file, 'r') as f:
    funding_data = json.load(f)

with open(civic_file, 'r') as f:
    civic_docs = json.load(f)

design_projects = []

for doc in civic_docs:
    text = doc.get('text', '')
    if 'Capital Improvement Projects' in text and 'Design' in text:
        lines = text.split('\n')
        for line in lines:
            line = line.strip()
            if line and len(line) < 80 and not any(x in line for x in ['Updates:', 'Schedule:', 'Recommended', 'Subject:', 'To:', 'Prepared by:']):
                if any(keyword in line.lower() for keyword in ['road', 'avenue', 'drive', 'park', 'beach', 'canyon', 'project']):
                    clean_name = re.sub(r'^[\d\.\s\-\•\u2022]+', '', line)
                    clean_name = re.sub(r'\s+', ' ', clean_name).strip()
                    if len(clean_name) > 5:
                        design_projects.append(clean_name)

unique_design = list(set(design_projects))

funding_dict = {}
for f in funding_data:
    amount = int(f['Amount'])
    if amount > 50000:
        funding_dict[f['Project_Name']] = amount

def normalize(name):
    if not name:
        return ''
    name = name.lower().strip()
    name = re.sub(r'\s+', ' ', name)
    name = re.sub(r'\([^\)]+\)', '', name)
    return re.sub(r'[^a-z0-9\s]', '', name)

count = 0
matches = []

for proj in unique_design:
    proj_norm = normalize(proj)
    if proj_norm:
        for funding_name, amount in funding_dict.items():
            fund_norm = normalize(funding_name)
            if proj_norm in fund_norm or fund_norm in proj_norm:
                count += 1
                matches.append({'project': proj, 'funding': funding_name, 'amount': amount})
                break

result = {'count': count, 'matches': matches}
print('__RESULT__:')
print(json.dumps(result))

